/** Neutral gray blur for Next/Image placeholder */
export const IMAGE_BLUR =
  "data:image/jpeg;base64,";

/** Slightly warmer blur for editorial / hero surfaces */
export const IMAGE_BLUR_WARM =
  "data:image/jpeg;base64,";

const BLUR_POOL = [IMAGE_BLUR, IMAGE_BLUR_WARM] as const;

/** Pick a stable blur placeholder from category key */
export function blurForCategory(category?: string): string {
  if (!category?.trim()) return IMAGE_BLUR;
  let hash = 0;
  for (let i = 0; i < category.length; i++) {
    hash = (hash + category.charCodeAt(i) * (i + 1)) % BLUR_POOL.length;
  }
  return BLUR_POOL[hash] ?? IMAGE_BLUR;
}
